mapper.select:
select a.test_id ,a.test_no ,a.create_date ,dbo.getCommonName('item_type_cd', a.item_type_cd) as item_type_cd ,b.item_cd ,b.item_name ,a.lot_no ,a.qty ,a.expiry_date ,dbo.getCustomerName(a.customer_cd) as customer_name ,dbo.getCommonName('pass_state', a.pass_state) as pass_state ,dbo.getCommonName('test_state', a.test_state) as test_state ,a.expiry_date ,a.shelf_life from tb_item_test_no a left outer join tb_item_mst b on a.item_cd = b.item_cd where a.create_date between #{strDate} and #{endDate}
AND a.test_no = #{testNo}
AND a.item_type_cd = #{itemTypeCd}
AND a.item_cd LIKE '%' + #{itemCd} + '%'
AND b.item_name LIKE '%' + #{itemName} + '%'
AND dbo.getCustomerName(a.customer_cd) LIKE '%' + #{customerName} + '%'
AND a.shelf_life = #{shelfLife}

mapper.update:
update tb_item_test_no
set    create_date  = #{item.createDate}
      ,customer_cd  = #{item.customerCd}
      ,make_no      = #{item.makeNo}
      ,lot_no       = #{item.lotNo}
      ,qty          = #{item.qty}
      ,pass_state   = #{item.passState}
      ,test_state   = #{item.testState}
      ,expiry_date  = #{item.expiryDate}
      ,shelf_life   = #{item.shelfLife}
      ,end_yn       = isnull(#{item.endYn}, 'N')
      ,upd_id       = #{item.userId}
      ,upd_dt       = getdate()
where  test_no      = #{item.testNo}

update tb_item_test_no
set pass_state   = #{passState}
   ,test_state   = #{testState}
   ,upd_id       = #{userId}
   ,upd_dt       = getdate()
where  test_no   = #{testNo}
